import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const Schema = z.object({

  god_status: z.object({
    current_persona: z.string().prefault('Bản tôn Chí Cao Thần'),
    concealment: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    // Giữ nguyên Enum tiếng Anh để tránh lỗi logic
    play_mode: z.enum(['Hedonism', 'Adventure']).prefault('Hedonism'),
    target_preference: z.enum(['Female_Only', 'All', 'Male_Only']).prefault('Female_Only'),
    // Mới thêm: Xúc xắc định mệnh (Số ngẫu nhiên tạo trước)
    fate_dice: z.coerce.number().transform(v => _.clamp(v, 1, 100)).prefault(50),
  }).or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),

  world_state: z.object({
    name: z.string().prefault('Thần Giới · Vĩnh Hằng Thánh Vực'),
    timeline: z.string().prefault('Vĩnh hằng'),
    chaos_level: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
  }).or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),

  current_target: z.object({
    name: z.string().prefault('Chưa có'),
    progress: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    strategy: z.string().prefault('Đang quan sát'),
  }).or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),

  apostles: z.record(
    z.string(),
    z.object({
      origin: z.string().prefault('Không rõ'),
      method: z.enum(['Marked', 'Romanced']).prefault('Romanced'),
      location: z.enum(['Party', 'Sanctuary', 'Mission']).prefault('Sanctuary'),

      love: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      submission: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      lust: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      loyalty: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50),
      mood: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50),
      arousal: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),

      corruption: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      bond: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      jealousy: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      fatigue: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),

      current_outfit: z.string().prefault('Mặc định'),
      current_title: z.string().prefault('Không'),

      outfits: z.record(z.string(), z.string()).prefault({}),
      titles: z.record(z.string(), z.string()).prefault({}),
      personality: z.record(z.string(), z.string()).prefault({}),
      weakness: z.record(z.string(), z.string()).prefault({}),
      fetish: z.record(z.string(), z.string()).prefault({}),
      skills: z.record(z.string(), z.string()).prefault({}),
    })
  ).transform(data => {
    const partyMembers = _(data).entries().filter(([k, v]) => v.location === 'Party').value();
    if (partyMembers.length > 3) {
      const toMove = partyMembers.slice(3);
      toMove.forEach(([name]) => {
        data[name].location = 'Sanctuary';
      });
    }
    return data;
  }).prefault({}),

  harem_relations: z.record(
    z.string(),
    z.record(
      z.string(),
      z.enum(['friendly', 'neutral', 'rival', 'hostile', 'intimate']).prefault('neutral')
    )
  ).prefault({}),

  world_archive: z.record(
    z.string(),
    z.object({
      timeline_altered: z.string().prefault('Chưa thay đổi'),
      chaos_caused: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      characters_taken: z.record(z.string(), z.boolean()).prefault({}),
    })
  ).prefault({}),

  adventure_log: z.record(
    z.string(),
    z.object({
      world: z.string().prefault('Không rõ'),
      description: z.string().prefault(''),
      $time: z.coerce.number().prefault(() => Date.now()),
    })
  ).transform(data => {
    return _(data).entries().sortBy('[1].$time').takeRight(20).fromPairs().value();
  }).prefault({}),

});

$(() => {
  registerMvuSchema(Schema);
});

