  <script type="module">
    function populateCharacterData() {
      const all_variables = getAllVariables();

      // 神明状态 - God Status
      const godStatus = _.get(all_variables, 'stat_data.god_status', {});
      const persona = godStatus.current_persona || 'Bản tôn Chí Cao Thần';
      const playMode = godStatus.play_mode || 'Hedonism';

      // 目标偏好 - Target Preference
      const targetPref = godStatus.target_preference || 'Female_Only';
      const prefText = {
        'Female_Only': '♀ Chỉ Nữ',
        'All': '⚥ Không giới hạn',
        'Male_Only': '♂ Chỉ Nam'
      }[targetPref] || '♀ Chỉ Nữ';

      // 命运骰子 - Fate Dice
      const fateDice = godStatus.fate_dice || 0;

      $('#god-persona').text(persona);
      $('#play-mode')
        .text(playMode === 'Hedonism' ? 'Chế độ Hưởng Lạc' : 'Chế độ Mạo Hiểm')
        .removeClass('mode-hedonism mode-adventure')
        .addClass(playMode === 'Hedonism' ? 'mode-hedonism' : 'mode-adventure');

      $('#target-pref').text(prefText);

      // 冒险模式显示骰子 - Show Dice in Adventure Mode
      if (playMode === 'Adventure') {
        $('#fate-row').show();
        $('#fate-value').text('🎲 ' + fateDice);
      } else {
        $('#fate-row').hide();
      }

      // 世界状态 - World State
      const worldState = _.get(all_variables, 'stat_data.world_state', {});
      const worldName = worldState.name || 'Thần Giới · Vĩnh Hằng Thánh Vực';
      const timeline = worldState.timeline || 'Vĩnh hằng';
      const chaosLevel = worldState.chaos_level || 0;

      $('#world-name').text(worldName);
      $('#world-timeline').text(timeline);
      $('#chaos-level').text(chaosLevel);
      $('#chaos-bar').css('width', chaosLevel + '%');

      // 攻略目标 - Current Target
      const currentTarget = _.get(all_variables, 'stat_data.current_target', {});
      const targetName = currentTarget.name || 'None';
      const targetProgress = currentTarget.progress || 0;
      const targetStrategy = currentTarget.strategy || 'Observing'; // Giữ nguyên hoặc dịch tùy ý, ở đây tôi sẽ dịch
      const strategyText = {
          'Observing': 'Đang quan sát',
          'Hunting': 'Đang săn đuổi',
          'Seducing': 'Đang quyến rũ',
          'Capturing': 'Đang bắt giữ'
      }[targetStrategy] || targetStrategy;

      if (targetName === 'None' || targetName === 'Chưa có') {
        $('#target-box').hide();
        $('#no-target').show();
      } else {
        $('#target-box').show();
        $('#no-target').hide();
        $('#target-name').text(targetName);
        $('#target-progress').text(targetProgress + '%');
        $('#target-bar').css('width', targetProgress + '%');
        $('#target-strategy').text(strategyText);
      }

      // 使徒列表 - Apostles List
      const apostles = _.get(all_variables, 'stat_data.apostles', {});
      const apostleEntries = Object.entries(apostles);

      if (apostleEntries.length === 0) {
        $('#apostle-list').html('<div class="empty-message">Chưa có Sứ đồ</div>');
      } else {
        let apostleHtml = '';
        apostleEntries.forEach(([name, data]) => {
          const location = data.location || 'Sanctuary';
          const locationClass = location === 'Party' ? 'party' : '';
          const locationText = location === 'Party' ? 'Tháp tùng' : location === 'Mission' ? 'Nhiệm vụ' : 'Thần giới';

          const love = data.love || 0;
          const submission = data.submission || 0;
          const lust = data.lust || 0;
          const loyalty = data.loyalty || 50;
          const corruption = data.corruption || 0;
          const bond = data.bond || 0;

          apostleHtml += `
            <div class="apostle-card">
              <div class="apostle-header">
                <span class="apostle-name">♛ ${name}</span>
                <span class="apostle-location ${locationClass}">${locationText}</span>
              </div>
              <div class="apostle-stats">
                <div class="mini-stat">
                  <div class="mini-stat-label">Ái</div>
                  <div class="mini-stat-value">${love}</div>
                </div>
                <div class="mini-stat">
                  <div class="mini-stat-label">Phục</div>
                  <div class="mini-stat-value">${submission}</div>
                </div>
                <div class="mini-stat">
                  <div class="mini-stat-label">Dục</div>
                  <div class="mini-stat-value">${lust}</div>
                </div>
                <div class="mini-stat">
                  <div class="mini-stat-label">Trung</div>
                  <div class="mini-stat-value">${loyalty}</div>
                </div>
                <div class="mini-stat">
                  <div class="mini-stat-label">Đọa</div>
                  <div class="mini-stat-value">${corruption}</div>
                </div>
                <div class="mini-stat">
                  <div class="mini-stat-label">Kết</div>
                  <div class="mini-stat-value">${bond}</div>
                </div>
              </div>
            </div>
          `;
        });
        $('#apostle-list').html(apostleHtml);
      }

      // 使徒数量统计 - Count
      const partyCount = apostleEntries.filter(([_, d]) => d.location === 'Party').length;
      const totalCount = apostleEntries.length;
      $('#apostle-count').text(`${partyCount}/3 Tháp tùng · ${totalCount} Tổng`);
    }

    function toggleSection($header) {
      const $content = $header.next('.section-content');
      const $icon = $header.find('.toggle-icon');
      $content.toggleClass('collapsed');
      $icon.toggleClass('collapsed');
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateCharacterData();

      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => {
        populateCharacterData();
      });

      $('.section-header').on('click', function() {
        toggleSection($(this));
      });
    }

    $(errorCatched(init));
  </script>
</head>
